module DescribeContactEvaluationResponse =
  struct
    type nonrec t =
      {
      evaluation: Evaluation.t option
        [@ocaml.doc
          "Information about the evaluation form completed for a specific contact."];
      evaluationForm: EvaluationFormContent.t option
        [@ocaml.doc "Information about the evaluation form."]}
    type nonrec error =
      [ `InternalServiceException of InternalServiceException.t 
      | `InvalidParameterException of InvalidParameterException.t 
      | `ResourceNotFoundException of ResourceNotFoundException.t 
      | `ThrottlingException of ThrottlingException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?evaluation =
      fun ?evaluationForm -> fun () -> { evaluation; evaluationForm }
    let error_of_json name json =
      match name with
      | "InternalServiceException" ->
          `InternalServiceException (InternalServiceException.of_json json)
      | "InvalidParameterException" ->
          `InvalidParameterException (InvalidParameterException.of_json json)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_json json)
      | "ThrottlingException" ->
          `ThrottlingException (ThrottlingException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "InternalServiceException" ->
          `InternalServiceException (InternalServiceException.of_xml xml)
      | "InvalidParameterException" ->
          `InvalidParameterException (InvalidParameterException.of_xml xml)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_xml xml)
      | "ThrottlingException" ->
          `ThrottlingException (ThrottlingException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `InternalServiceException e ->
          `Assoc
            [("error", (`String "InternalServiceException"));
            ("details", (InternalServiceException.to_json e))]
      | `InvalidParameterException e ->
          `Assoc
            [("error", (`String "InvalidParameterException"));
            ("details", (InvalidParameterException.to_json e))]
      | `ResourceNotFoundException e ->
          `Assoc
            [("error", (`String "ResourceNotFoundException"));
            ("details", (ResourceNotFoundException.to_json e))]
      | `ThrottlingException e ->
          `Assoc
            [("error", (`String "ThrottlingException"));
            ("details", (ThrottlingException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("Evaluation", (Option.map x.evaluation ~f:Evaluation.to_value));
        ("EvaluationForm",
          (Option.map x.evaluationForm ~f:EvaluationFormContent.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let evaluationForm =
        (Option.map ~f:EvaluationFormContent.of_xml)
          (Xml.child xml_arg0 "EvaluationForm") in
      let evaluation =
        (Option.map ~f:Evaluation.of_xml) (Xml.child xml_arg0 "Evaluation") in
      make ?evaluationForm ?evaluation ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let evaluationForm =
        field_map json__ "EvaluationForm" EvaluationFormContent.of_json in
      let evaluation = field_map json__ "Evaluation" Evaluation.of_json in
      make ?evaluationForm ?evaluation ()
    let to_json v = composed_to_json to_value v
