      make
        (List.map
           ((Xml.all_children x) |>
              (List.filter
                 ~f:(function
                     | `Data s ->
                         (match Stdlib.String.trim s with
                          | "" -> false
                          | _ -> true)
                     | _ -> true))) ~f:GroupingV2.of_xml)
    let of_json j =
      list_of_json ~kind:"GroupingsV2" ~of_json:GroupingV2.of_json j
    let to_json v = composed_to_json to_value v
  end
module GetMetricDataV2Request =
